'use strict';
/**
 * apply-prequalified-granularity.cjs  (ALT-464 / HungerBox prequalified-question granularity)
 *
 * Adds two new tables to support the per-project granularity toggle and
 * company-level (vs site-level) prequalified-answer storage.
 *
 * =====================================================================
 * SCHEMA CONTEXT (from apply-hungerbox-company-sites.cjs, 2026-06-28)
 * =====================================================================
 *
 * public.company_site
 *   PK:  site_id  bigint GENERATED BY DEFAULT AS IDENTITY
 *   UNIQUE (company_id, city_id)   — city_id is NOT NULL
 *   Cols: total_employees integer, commercial_model text, notes text,
 *         is_feasible boolean, is_dnc boolean,
 *         created_at/updated_at/deleted_at timestamptz
 *   FKs:  company_id → company_master.company_id (CASCADE)
 *         city_id    → city_master.city_id (RESTRICT)
 *
 * Note on company-level storage:
 *   company_site requires a real city_id (FK → city_master, NOT NULL).
 *   We therefore cannot use a sentinel "null city" row.
 *   Instead we introduce company_hb_prequal — one row per company —
 *   to hold the company-wide prequalified answers when the project's
 *   granularity is set to 'company'.
 *
 * =====================================================================
 * NEW TABLES
 * =====================================================================
 *
 * public.project_hb_setting
 *   One row per project. Stores the prequalified-question granularity
 *   choice for that project.
 *
 *   project_id               bigint   PK   FK → project_master.project_id
 *   prequalified_granularity text     NOT NULL DEFAULT 'site'
 *                                     CHECK IN ('company', 'site')
 *   updated_by               text
 *   updated_at               timestamptz
 *
 * public.company_hb_prequal
 *   One row per company. Holds the company-wide prequalified answers
 *   used when granularity = 'company'.  Separate from company_site so
 *   the site-level rows are undisturbed if the toggle switches back.
 *
 *   company_id        bigint   PK   FK → company_master.company_id (CASCADE)
 *   total_employees   integer
 *   commercial_model  text
 *   notes             text
 *   updated_by        text
 *   updated_at        timestamptz
 *
 * public.hb_company_prequal_history
 *   Audit trail for edits to company_hb_prequal (mirrors hb_site_history).
 *
 *   history_id   bigint PK GENERATED BY DEFAULT AS IDENTITY
 *   company_id   bigint NOT NULL FK → company_master.company_id (CASCADE)
 *   changed_by   text   NOT NULL
 *   changed_at   timestamptz NOT NULL DEFAULT now()
 *   field_name   text   NOT NULL
 *   old_value    text
 *   new_value    text
 *
 * =====================================================================
 * STAGED ONLY — node -c to syntax-check; DO NOT execute against the DB
 * until the owner approves and HUNGERBOX_FEATURES is flipped to true.
 *
 * Depends on:
 *   apply-hungerbox-company-sites.cjs   (company_site + hb_site_history)
 *
 * To apply later:
 *   cd new-code/migration && node apply-prequalified-granularity.cjs
 * =====================================================================
 */
require('dotenv').config();
const { Pool } = require('pg');

const SQL = `
-- =====================================================================
-- HungerBox — prequalified-question granularity toggle  (ALT-464)
-- =====================================================================

-- ---------------------------------------------------------------------
-- 1. public.project_hb_setting
--    Per-project HungerBox settings. First setting: granularity toggle.
-- ---------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.project_hb_setting (
  project_id                bigint      PRIMARY KEY,

  -- 'site'    => prequalified answers are stored per company_site row (today's behaviour)
  -- 'company' => one company-wide answer set stored in company_hb_prequal
  prequalified_granularity  text        NOT NULL DEFAULT 'site',

  updated_by                text,
  updated_at                timestamptz,

  CONSTRAINT project_hb_setting_fk_project
    FOREIGN KEY (project_id) REFERENCES public.project_master (project_id)
    ON DELETE CASCADE,

  CONSTRAINT project_hb_setting_granularity_chk
    CHECK (prequalified_granularity IN ('company', 'site'))
);

-- ---------------------------------------------------------------------
-- 2. public.company_hb_prequal
--    Company-wide prequalified answers (used when granularity='company').
--    One row per company (PK = company_id).
--    Kept separate from company_site so switching back to 'site' mode
--    does not disturb the per-site rows.
-- ---------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.company_hb_prequal (
  company_id        bigint      PRIMARY KEY,

  -- Prequalified answers (mirrors company_site columns)
  total_employees   integer,
  commercial_model  text,
  notes             text,

  -- Audit
  updated_by        text,
  updated_at        timestamptz,

  CONSTRAINT company_hb_prequal_fk_company
    FOREIGN KEY (company_id) REFERENCES public.company_master (company_id)
    ON DELETE CASCADE,

  CONSTRAINT company_hb_prequal_employees_chk
    CHECK (total_employees IS NULL OR total_employees >= 0)
);

-- ---------------------------------------------------------------------
-- 3. public.hb_company_prequal_history
--    Audit trail for company-level prequalified-answer edits.
--    Mirrors hb_site_history structure.
-- ---------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.hb_company_prequal_history (
  history_id   bigint      GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  company_id   bigint      NOT NULL,
  changed_by   text        NOT NULL,
  changed_at   timestamptz NOT NULL DEFAULT now(),
  field_name   text        NOT NULL,
  old_value    text,
  new_value    text,

  CONSTRAINT hb_company_prequal_history_fk_company
    FOREIGN KEY (company_id) REFERENCES public.company_master (company_id)
    ON DELETE CASCADE
);

-- ---------------------------------------------------------------------
-- 4. Indexes
-- ---------------------------------------------------------------------
CREATE INDEX IF NOT EXISTS hb_company_prequal_history_company_id_idx
  ON public.hb_company_prequal_history (company_id, changed_at DESC);

-- ---------------------------------------------------------------------
-- 5. GRANTS
-- ---------------------------------------------------------------------
REVOKE ALL ON public.project_hb_setting             FROM anon;
REVOKE ALL ON public.project_hb_setting             FROM PUBLIC;
REVOKE ALL ON public.company_hb_prequal             FROM anon;
REVOKE ALL ON public.company_hb_prequal             FROM PUBLIC;
REVOKE ALL ON public.hb_company_prequal_history     FROM anon;
REVOKE ALL ON public.hb_company_prequal_history     FROM PUBLIC;

GRANT SELECT, INSERT, UPDATE, DELETE ON public.project_hb_setting         TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.company_hb_prequal         TO authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.hb_company_prequal_history TO authenticated;

GRANT USAGE ON SEQUENCE public.hb_company_prequal_history_history_id_seq TO authenticated;
`;

(async () => {
  const pg = new Pool({ connectionString: process.env.PG_CONNECTION_STRING });
  const client = await pg.connect();
  try {
    await client.query('BEGIN');
    await client.query(SQL);
    await client.query('COMMIT');
    console.log('APPLIED apply-prequalified-granularity OK (committed).');
  } catch (e) {
    await client.query('ROLLBACK');
    console.error('APPLY FAILED, rolled back:', e.message);
    client.release();
    await pg.end();
    process.exit(1);
  }

  // === VERIFY ===
  const tables = ['project_hb_setting', 'company_hb_prequal', 'hb_company_prequal_history'];
  for (const tbl of tables) {
    const cols = await client.query(`
      SELECT column_name, data_type, is_nullable, column_default
      FROM information_schema.columns
      WHERE table_schema='public' AND table_name=$1
      ORDER BY ordinal_position
    `, [tbl]);
    console.log(`\n=== ${tbl} COLUMNS ===`);
    console.log(JSON.stringify(cols.rows, null, 2));
  }

  const idx = await client.query(`
    SELECT indexname FROM pg_indexes
    WHERE schemaname='public'
      AND tablename IN ('project_hb_setting','company_hb_prequal','hb_company_prequal_history')
    ORDER BY indexname
  `);
  console.log('\n=== INDEXES ===');
  console.log(JSON.stringify(idx.rows.map(r => r.indexname), null, 2));

  client.release();
  await pg.end();
})().catch(e => { console.error('ERR:', e.message); process.exit(1); });
